from flask import Flask, request, jsonify
import random
import string

app = Flask(__name__)

auth_codes = {}
tokens = {}

def generate_code(length=10):
    return ''.join(random.choices(string.ascii_letters + string.digits, k=length))

@app.route('/authorize', methods=['POST'])
def authorize():
    user_id = request.json.get('user_id')
    if not user_id:
        return jsonify({'error': 'User ID is required'}), 400
    
    code = generate_code()
    auth_codes[code] = user_id
    return jsonify({'authorization_code': code}), 200

@app.route('/token', methods=['POST'])
def token():
    code = request.json.get('authorization_code')
    if code not in auth_codes:
        return jsonify({'error': 'Invalid authorization code'}), 400
    
    user_id = auth_codes[code]
    token = generate_code()
    tokens[token] = user_id
    return jsonify({'access_token': token}), 200

@app.route('/validate', methods=['POST'])
def validate():
    token = request.json.get('access_token')
    if token in tokens:
        return jsonify({'valid': True, 'user_id': tokens[token]}), 200
    return jsonify({'valid': False}), 400

if __name__ == '__main__':
    app.run(debug=True)